/* MISA Esports - Live Data Loader
 * Fetches live.json (generated by GitHub Actions from PandaScore)
 * and merges it into the static MISA_DATA object.
 * Falls back to static data if fetch fails or data is stale.
 */

window.__misaDataReady = (async function () {
  try {
    const res = await fetch('assets/data/live.json?v=' + Date.now());
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const live = await res.json();

    // Skip if no fetch timestamp (stub file)
    if (!live._meta?.fetchedAt) {
      console.log('[MISA] Live data is a stub, using static data');
      return;
    }

    // Skip if data is older than 48 hours
    const fetchedAt = new Date(live._meta.fetchedAt);
    const ageHours = (Date.now() - fetchedAt.getTime()) / 3600000;
    if (ageHours > 48) {
      console.warn('[MISA] Live data is stale (' + Math.round(ageHours) + 'h old), using static data');
      return;
    }

    // Merge branches (roster, standings)
    if (live.branches) {
      for (const [key, branchData] of Object.entries(live.branches)) {
        if (!MISA_DATA.branches[key]) continue;

        // Merge roster: keep static images as fallback
        if (branchData.roster?.length) {
          MISA_DATA.branches[key].roster = branchData.roster.map((p, i) => {
            const staticPlayer = MISA_DATA.branches[key].roster[i] || {};
            return {
              ...staticPlayer,
              ...p,
              image: p.image || staticPlayer.image || ''
            };
          });
        }

        // Merge teamLogo
        if (branchData.teamLogo) {
          MISA_DATA.branches[key].teamLogo = branchData.teamLogo;
        }

        // Override standings if present
        if (branchData.standings) {
          MISA_DATA.branches[key].standings = branchData.standings;
        }
      }
    }

    // Merge matches (full override if present and non-empty)
    if (live.matches?.upcoming?.length) {
      MISA_DATA.matches.upcoming = live.matches.upcoming;
    }
    if (live.matches?.recent?.length) {
      MISA_DATA.matches.recent = live.matches.recent;
    }

    console.log('[MISA] Live data loaded (' + Math.round(ageHours) + 'h ago)');
  } catch (err) {
    console.warn('[MISA] Could not load live data, using static fallback:', err.message);
  }
})();
